\title{UXBench: Benchmarking User Experience in AI Assistants}

% \author{Mengze Hong$^{1}$, Zeng Xia$^{1}$, Henry Lei$^{1}$,  Chen Jason Zhang$^{2}$, Di Jiang$^{2}$, Julian Liang$^{1*}$\\
%  $^{1}$Yuanbao Team, Tencent, $^{2}$Hong Kong Polytechnic University\\
